// Store form input for downstream nodes
const formData = $input.first().json;
return [{ json: { _jobRole: formData['Job Role'] || '', _techStack: formData['Tech Stack'] || '', _country: formData['Country'] || '' } }];

const items = $input.all();

// Extract stored form data from the first item that has it
let jobRole = '';
let techStack = '';
let country = '';
for (const item of items) {
  if (item.json._jobRole) { jobRole = item.json._jobRole; techStack = item.json._techStack || ''; country = item.json._country || ''; break; }
}

function clean(html) {
  return (html || '').replace(/<[^>]*>/g, '').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/\s+/g, ' ').trim();
}

function extractSalary(desc, data) {
  if (data.salary) return String(data.salary);
  if (data.salaryMin || data.salaryMax) {
    const parts = [];
    if (data.salaryCurrency) parts.push(data.salaryCurrency);
    if (data.salaryMin) parts.push(Number(data.salaryMin).toLocaleString());
    if (data.salaryMax) parts.push('- ' + Number(data.salaryMax).toLocaleString());
    if (data.salaryPeriod) parts.push(data.salaryPeriod);
    return parts.join(' ');
  }
  const m = desc.match(/[\$\£\€\₹]\s?[\d,]+(?:\s?[-–]\s?[\$\£\€\₹]?\s?[\d,]+)?(?:\s?(?:k|K|LPA|lpa|pa|p\.a\.|per year|per annum|yearly|annually))?/);
  if (m) return m[0].trim();
  return 'Not mentioned';
}

function extractVisa(desc) {
  const lower = desc.toLowerCase();
  if (lower.includes('visa sponsor') || lower.includes('visa support') || lower.includes('we sponsor') || lower.includes('sponsorship available') || lower.includes('will sponsor')) return 'Yes';
  if (lower.includes('no visa') || lower.includes('no sponsorship') || lower.includes('must be authorized') || lower.includes('must be eligible') || lower.includes('right to work') || lower.includes('authorized to work') || lower.includes('work permit required')) return 'No';
  return 'Not mentioned';
}

function extractCompanyInfo(desc) {
  const patterns = [/about\s+(?:us|the\s+company|our\s+company)[:\s]*([^.]+\.)/i, /(?:we\s+are|we're)\s+(?:a|an)\s+([^.]+\.)/i];
  for (const p of patterns) {
    const m = desc.match(p);
    if (m && m[1] && m[1].length > 20) return m[1].trim().substring(0, 200);
  }
  const fundingMatch = desc.match(/(?:raised|funding|series\s+[a-e]|seed\s+round|venture|backed\s+by)[^.]+\./i);
  if (fundingMatch) return fundingMatch[0].trim().substring(0, 200);
  return '';
}

function extractCompanySize(desc) {
  const empMatch = desc.match(/(\d[\d,]*)\+?\s*(?:employees|team members|people|staff)/i);
  if (empMatch) {
    const num = parseInt(empMatch[1].replace(/,/g, ''));
    if (num < 50) return 'Startup (<50)';
    if (num < 200) return 'Small (50-200)';
    if (num < 1000) return 'Medium (200-1K)';
    if (num < 5000) return 'Large (1K-5K)';
    return 'Enterprise (5K+)';
  }
  const lower = desc.toLowerCase();
  if (lower.includes('startup') || lower.includes('early stage')) return 'Startup';
  if (lower.includes('fortune 500') || lower.includes('multinational')) return 'Enterprise (5K+)';
  return '';
}

// Category rules based on keywords
function categorize(title, desc) {
  const t = (title + ' ' + desc).toLowerCase();
  if (t.includes('frontend') || t.includes('front-end') || t.includes('front end') || t.includes('react') || t.includes('angular') || t.includes('vue')) return 'Frontend';
  if (t.includes('backend') || t.includes('back-end') || t.includes('back end') || t.includes('django') || t.includes('spring') || t.includes('express') || t.includes('fastapi')) return 'Backend';
  if (t.includes('fullstack') || t.includes('full-stack') || t.includes('full stack')) return 'Fullstack';
  if (t.includes('devops') || t.includes('sre') || t.includes('infrastructure') || t.includes('kubernetes') || t.includes('terraform') || t.includes('ci/cd') || t.includes('platform engineer')) return 'DevOps';
  if (t.includes('data scientist') || t.includes('data engineer') || t.includes('data analyst') || t.includes('machine learning') || t.includes('ml engineer') || t.includes('ai ') || t.includes('analytics')) return 'Data';
  if (t.includes('mobile') || t.includes('ios') || t.includes('android') || t.includes('flutter') || t.includes('react native') || t.includes('swift') || t.includes('kotlin')) return 'Mobile';
  if (t.includes('design') || t.includes('ux') || t.includes('ui ') || t.includes('figma') || t.includes('product design')) return 'Design';
  if (t.includes('qa') || t.includes('quality') || t.includes('test') || t.includes('sdet') || t.includes('automation test')) return 'QA';
  if (t.includes('product manager') || t.includes('program manager') || t.includes('project manager') || t.includes('scrum') || t.includes('agile lead')) return 'PM';
  if (t.includes('marketing') || t.includes('seo') || t.includes('growth') || t.includes('content')) return 'Marketing';
  if (t.includes('sales') || t.includes('business development') || t.includes('account exec')) return 'Sales';
  if (t.includes('security') || t.includes('cybersec') || t.includes('infosec') || t.includes('penetration')) return 'Security';
  if (t.includes('cloud') || t.includes('aws') || t.includes('azure') || t.includes('gcp')) return 'Cloud';
  return 'Other';
}

// Synonym map - expand role to include similar titles
const SYNONYMS = {
  'engineer': ['developer', 'programmer', 'coder', 'dev', 'sde', 'swe'],
  'developer': ['engineer', 'programmer', 'coder', 'dev', 'sde', 'swe'],
  'programmer': ['developer', 'engineer', 'coder', 'dev'],
  'software': ['web', 'application', 'app', 'platform'],
  'frontend': ['front-end', 'front end', 'ui', 'react', 'angular', 'vue', 'client-side'],
  'backend': ['back-end', 'back end', 'server', 'api', 'server-side'],
  'fullstack': ['full-stack', 'full stack', 'frontend', 'backend'],
  'devops': ['sre', 'infrastructure', 'platform', 'cloud', 'reliability'],
  'data': ['analytics', 'bi', 'machine learning', 'ml', 'ai'],
  'mobile': ['ios', 'android', 'flutter', 'react native', 'app'],
  'qa': ['test', 'quality', 'sdet', 'automation'],
  'test': ['qa', 'quality', 'sdet', 'automation'],
  'design': ['ux', 'ui', 'figma', 'product design', 'graphic'],
  'manager': ['lead', 'head', 'director', 'principal', 'senior'],
  'lead': ['manager', 'head', 'principal', 'senior', 'staff'],
  'senior': ['sr', 'lead', 'principal', 'staff', 'experienced'],
  'junior': ['jr', 'entry', 'associate', 'trainee', 'intern', 'fresher'],
  'architect': ['principal', 'staff', 'lead engineer', 'technical lead'],
  'analyst': ['associate', 'consultant', 'specialist'],
  'consultant': ['analyst', 'advisor', 'specialist'],
  'security': ['cybersecurity', 'infosec', 'appsec', 'penetration'],
  'cloud': ['aws', 'azure', 'gcp', 'infrastructure', 'devops'],
  'product': ['pm', 'program', 'project'],
  'marketing': ['growth', 'seo', 'content', 'digital'],
  'sales': ['business development', 'account', 'revenue']
};

function expandRole(role) {
  const words = role.toLowerCase().split(/[\s,\/]+/).filter(w => w.length > 1);
  const expanded = new Set(words);
  for (const w of words) {
    if (SYNONYMS[w]) {
      SYNONYMS[w].forEach(s => expanded.add(s));
    }
  }
  return [...expanded];
}

// Relevance scoring with synonym expansion
function scoreJob(title, desc, role, stack) {
  let score = 0;
  const titleLower = title.toLowerCase();
  const descLower = desc.toLowerCase();
  const expandedRole = expandRole(role);
  const stackWords = stack.toLowerCase().split(/[\s,\/]+/).filter(w => w.length > 1);

  // Title matches (highest weight)
  for (const w of expandedRole) {
    if (titleLower.includes(w)) score += 25;
  }
  for (const w of stackWords) {
    if (titleLower.includes(w)) score += 20;
  }

  // Description matches
  for (const w of expandedRole) {
    if (descLower.includes(w)) score += 8;
  }
  for (const w of stackWords) {
    if (descLower.includes(w)) score += 12;
  }

  // Normalize to 0-100
  const maxPossible = (expandedRole.length * 33) + (stackWords.length * 32);
  return maxPossible > 0 ? Math.min(100, Math.round((score / maxPossible) * 100)) : 50;
}

const normalized = items.map(item => {
  const d = item.json;
  if (d._jobRole || d.error || d.statusCode >= 400 || (typeof d === 'string')) return [];

  // Remotive
  if (d.jobs && !Array.isArray(d.data) && !d.jobTitle && !d.companyName) {
    return d.jobs.map(j => {
      const desc = clean(j.description || '');
      return { json: {
        title: j.title || '', company: j.company_name || '', link: j.url || '',
        description: desc.substring(0, 800), posted_date: j.publication_date || '',
        source: 'Remotive', location: j.candidate_required_location || 'Remote',
        salary: extractSalary(desc, j), job_type: (j.job_type || '').replace(/_/g, ' ') || 'Not mentioned',
        visa_sponsored: extractVisa(desc), company_size: extractCompanySize(desc), company_info: extractCompanyInfo(desc)
      }};
    });
  }

  // Arbeitnow
  if (d.data && Array.isArray(d.data)) {
    return d.data.map(j => {
      const desc = clean(j.description || '');
      return { json: {
        title: j.title || '', company: j.company_name || '', link: j.url || '',
        description: desc.substring(0, 800), posted_date: j.created_at || '',
        source: 'Arbeitnow', location: j.location || (j.remote ? 'Remote' : 'Not mentioned'),
        salary: extractSalary(desc, j), job_type: j.remote ? 'Remote' : 'On-site',
        visa_sponsored: extractVisa(desc), company_size: extractCompanySize(desc), company_info: extractCompanyInfo(desc)
      }};
    });
  }

  // Jobicy
  if (d.jobs && Array.isArray(d.jobs) && d.jobs[0] && d.jobs[0].jobTitle) {
    return d.jobs.map(j => {
      const desc = clean(j.jobDescription || '');
      return { json: {
        title: j.jobTitle || '', company: j.companyName || '', link: j.url || '',
        description: desc.substring(0, 800), posted_date: j.pubDate || '',
        source: 'Jobicy', location: j.jobGeo || 'Remote',
        salary: extractSalary(desc, j), job_type: (Array.isArray(j.jobType) ? j.jobType.join(', ') : j.jobType) || 'Not mentioned',
        visa_sponsored: extractVisa(desc), company_size: extractCompanySize(desc), company_info: extractCompanyInfo(desc)
      }};
    });
  }

  // LinkedIn (positionName)
  if (d.positionName || (d.title && d.companyName && d.link)) {
    const desc = clean(d.descriptionText || d.description || '');
    return [{ json: {
      title: d.positionName || d.title || '', company: d.companyName || d.company || '',
      link: d.link || d.applyUrl || d.url || '',
      description: desc.substring(0, 800), posted_date: d.postedAt || d.publishedAt || d.postedTime || '',
      source: 'LinkedIn', location: d.location || d.formattedLocation || 'Not mentioned',
      salary: d.salary || extractSalary(desc, d), job_type: d.contractType || d.employmentType || d.workType || 'Not mentioned',
      visa_sponsored: extractVisa(desc), company_size: d.companySize || extractCompanySize(desc),
      company_info: d.companyDescription ? clean(d.companyDescription).substring(0, 200) : extractCompanyInfo(desc)
    }}];
  }

  // Naukri (Job Title)
  if (d.jobId || d['Job Title'] || (d.title && d.jdURL)) {
    const desc = clean(d.Description || d.description || d.jobDescription || d['Job Description'] || '');
    return [{ json: {
      title: d['Job Title'] || d.title || d.designation || '',
      company: d.Company || d['Company Name'] || d.companyName || d.company || '',
      link: d['Job URL'] || d.jdURL || d.url || '', description: desc.substring(0, 800),
      posted_date: d['Posted Time'] || d.createdDate || d.postedDate || d['Posted Date'] || '',
      source: 'Naukri',
      location: d['Location'] || d.placeholders?.find(p => p.type === 'location')?.label || d.location || 'Not mentioned',
      salary: d['Salary'] || d.placeholders?.find(p => p.type === 'salary')?.label || d.salary || extractSalary(desc, d),
      job_type: d['Experience'] || d.placeholders?.find(p => p.type === 'experience')?.label || 'Not mentioned',
      visa_sponsored: extractVisa(desc),
      company_size: d.ambitionBoxData?.CompanySize || d['Company Size'] || extractCompanySize(desc),
      company_info: d.ambitionBoxData?.About ? clean(d.ambitionBoxData.About).substring(0, 200) : extractCompanyInfo(desc)
    }}];
  }

  // Fallback
  const desc = clean(d.description || d.jobDescription || '');
  if (!d.title && !d.jobTitle && !d.positionName) return [];
  return [{ json: {
    title: d.title || d.jobTitle || d.positionName || '',
    company: d.company || d.company_name || d.companyName || '',
    link: d.url || d.link || '', description: desc.substring(0, 800),
    posted_date: d.publication_date || d.created_at || d.pubDate || d.postedAt || '',
    source: 'Other', location: d.candidate_required_location || d.location || d.jobGeo || 'Not mentioned',
    salary: extractSalary(desc, d), job_type: d.job_type || d.jobType || 'Not mentioned',
    visa_sponsored: extractVisa(desc), company_size: extractCompanySize(desc), company_info: extractCompanyInfo(desc)
  }}];
});

// Flatten, score, categorize, filter, sort
const flat = normalized.flat().filter(i => i.json && i.json.title);
const scored = flat.map(item => {
  const j = item.json;
  const relevance = scoreJob(j.title, j.description, jobRole, techStack);
  const category = categorize(j.title, j.description);
  return { json: { ...j, relevance: relevance + '%', category } };
});

// Filter: must have at least 1 expanded role keyword in title or description
const expandedRoleWords = expandRole(jobRole);
const filtered = scored.filter(item => {
  const rel = parseInt(item.json.relevance);
  if (rel >= 10) return true;
  const titleLower = item.json.title.toLowerCase();
  const descLower = (item.json.description || '').toLowerCase();
  return expandedRoleWords.some(w => titleLower.includes(w) || descLower.includes(w));
});

// Sort by relevance (highest first), then by date
filtered.sort((a, b) => {
  const ra = parseInt(a.json.relevance);
  const rb = parseInt(b.json.relevance);
  if (rb !== ra) return rb - ra;
  return new Date(b.json.posted_date || 0) - new Date(a.json.posted_date || 0);
});

return filtered;
